import json
from web3 import Web3

class EthereumWalletAuthService:
    def __init__(self):
        self.web3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'))

    def verify_signature(self, signed_message, address):
        try:
            recovered_address = self.web3.eth.account.recoverHash(signed_message)
            if recovered_address == address:
                return True
            else:
                return False
        except ValueError as e:
            print(f'Error verifying signature: {e}')
            return False